function saveTodayAttendance() {
    const classVal = document.getElementById('class-select') ? document.getElementById('class-select').value : 'm3';
    const roomVal = document.getElementById('room-select') ? document.getElementById('room-select').value : '1';
    const roster = (studentRosters[classVal] && studentRosters[classVal][roomVal]) ? studentRosters[classVal][roomVal] : studentRosters['m3']['1'];
    const studentIds = roster.map(s => s.id);

    const records = {};
    let presentCount = 0;
    let lateCount = 0;
    let leaveCount = 0;
    let absentCount = 0;
    let fullyMarked = true;

    studentIds.forEach(id => {
        const tabTable = document.getElementById('attendance-today-content');
        const actionCell = tabTable ? tabTable.querySelector('#action-' + id) : null;
        if (!actionCell) return;

        const badge = actionCell.querySelector('.status-badge');
        if (!badge) {
            fullyMarked = false;
            return;
        }

        if (badge.classList.contains('present')) {
            records[id] = 'present';
            presentCount++;
        } else if (badge.classList.contains('late')) {
            records[id] = 'late';
            lateCount++;
        } else if (badge.classList.contains('leave')) {
            records[id] = 'leave';
            leaveCount++;
        } else if (badge.classList.contains('absent')) {
            records[id] = 'absent';
            absentCount++;
        }
    });

    if (!fullyMarked) {
        showToast('บันทึกไม่สำเร็จ', 'กรุณาทำการเช็คชื่อนักเรียนให้ครบถ้วนทุกคนก่อนกดบันทึกครับ', 'warning');
        return;
    }

    const history = getAttendanceHistory();
    const dateInput = document.querySelector('#panel-attendance #attendance-date-select');
    const targetDateStr = dateInput ? formatToThaiDate(dateInput.value) : getTodayThaiDate();

    const newEntry = {
        date: targetDateStr,
        class: classVal,
        room: roomVal,
        total: studentIds.length,
        present: presentCount,
        late: lateCount,
        leave: leaveCount,
        absent: absentCount,
        rate: Math.round(((presentCount + lateCount + leaveCount) / studentIds.length) * 100),
        records: records
    };

    // Avoid duplicate dates, classes, and rooms by replacing
    const existingIndex = history.findIndex(h => h.date === targetDateStr && (h.class || 'm3') === classVal && (h.room || '1') === roomVal);
    if (existingIndex !== -1) {
        history[existingIndex] = newEntry;
    } else {
        history.unshift(newEntry);
    }

    localStorage.setItem('lms-attendance-history', JSON.stringify(history));

    const classLabel = classVal === 'm1' ? 'ม.1' : classVal === 'm2' ? 'ม.2' : classVal === 'm3' ? 'ม.3' : 'ม.3';
    const roomLabel = roomVal ? `/${roomVal}` : '/1';
    showToast('บันทึกสำเร็จ', `บันทึกรายงานข้อมูลการเข้าเรียนของห้อง ${classLabel}${roomLabel} วันที่ ${targetDateStr} เรียบร้อยแล้ว!`, 'success');

    // Broadcast an event to student dashboard to notify them about saved history
    bc.postMessage({
        type: 'ATTENDANCE_SAVED',
        date: targetDateStr,
        class: classVal,
        room: roomVal,
        records: records
    });

    renderAttendanceHistory();
    updateStatsGrid();
    updateAttendanceSummary();
}

